readline.on('line', line => {
  input.push(line);
  if (i === 0) {
    T = parseInt(line);
  }
  i++;
  if (i === T * 2 + 1) {
    for (let t = 0; t < T; t++) {
      let n = parseInt(input[t * 2 + 1]);
      let arr = input[t * 2 + 2].split(' ').map(Number);
      for (let i = n - 1; i >= 0; i--) {
        console.log(arr[i]);
      }
    }
    readline.close();
  }
});
